public void testContainsWithEmptyBuffer() {
    StrBuilder sb = new StrBuilder("test");
    sb.clear();
    assertFalse("Empty buffer should not contain any character", sb.contains('t'));
    assertEquals("Empty buffer should return -1 for indexOf", -1, sb.indexOf('t'));
}

public void testContainsAfterPartialDelete() {
    StrBuilder sb = new StrBuilder("abcdefgh");
    sb.delete(4, 8);
    assertFalse("Should not find character beyond size after delete", sb.contains('e'));
    assertFalse("Should not find character beyond size after delete", sb.contains('h'));
    assertTrue("Should find character within size", sb.contains('d'));
    assertEquals("Should return -1 for character beyond size", -1, sb.indexOf('f'));
    assertEquals("Should return correct index for character within size", 3, sb.indexOf('d'));
}

public void testIndexOfWithStartIndexBeyondSize() {
    StrBuilder sb = new StrBuilder("hello");
    sb.setLength(3);
    assertEquals("indexOf should return -1 when startIndex >= size", -1, sb.indexOf('l', 3));
    assertEquals("indexOf should return -1 when startIndex > size", -1, sb.indexOf('l', 5));
    assertEquals("indexOf should work when startIndex < size", 2, sb.indexOf('l', 2));
}
